import{_ as a,o,c as t,ae as r}from"./chunks/framework.B7wCLpXk.js";const l="/assets/ultrahand.CL-UQIzq.gif",f=JSON.parse('{"title":"Ultrahamd","description":"","frontmatter":{},"headers":[],"relativePath":"homebrew/ultrahand.md","filePath":"homebrew/ultrahand.md"}'),i={name:"homebrew/ultrahand.md"};function n(s,e,h,d,c,u){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="ultrahamd" tabindex="-1">Ultrahamd <a class="header-anchor" href="#ultrahamd" aria-label="Permalink to &quot;Ultrahamd&quot;">​</a></h1><p>Ultrahand is an overlay menu developed by <a href="https://github.com/ppkantorski" target="_blank" rel="noreferrer">WerWolv</a>, Ultrahand is comparable to Rosalina menu on the 3DS and its purpose is to be able to load community made overlays for Homebrew apps and sysmodules that can be accessed at any time. Below you can find common use cases for Ultrahand. The official Github page for Ultrahand can be found <a href="https://github.com/ppkantorski/Ultrahand-Overlay" target="_blank" rel="noreferrer">here</a>.</p><h3 id="common-use-cases-for-ultrahand" tabindex="-1">Common use cases for Ultrahand: <a class="header-anchor" href="#common-use-cases-for-ultrahand" aria-label="Permalink to &quot;Common use cases for Ultrahand:&quot;">​</a></h3><ul><li>Load community made Ultrahand overlays</li><li>Viewing the temperatures/clock speeds of your hardware</li><li>Editing sysmodule configs on the fly (if applicable)</li><li>Editing Homebrew app configs on the fly (if applicable)</li><li>Toggling cheats easily</li><li>Toggling sysmodules</li></ul><h2 id="installation-requirements" tabindex="-1">Installation requirements: <a class="header-anchor" href="#installation-requirements" aria-label="Permalink to &quot;Installation requirements:&quot;">​</a></h2><ul><li>An archive manager like <a href="https://www.7-zip.org/" target="_blank" rel="noreferrer">7-Zip</a></li><li>The latest release of <a href="https://github.com/ppkantorski/Ultrahand-Overlayreleases/" target="_blank" rel="noreferrer">Ultrahand</a> (the <code>sdout.zip</code> file)</li></ul><h2 id="installation-instructions" tabindex="-1">Installation instructions: <a class="header-anchor" href="#installation-instructions" aria-label="Permalink to &quot;Installation instructions:&quot;">​</a></h2><ol><li>Boot into hekate and go to <code>Tools</code> &gt; <code>USB Tools</code> &gt; <code>SD Card</code>, then plug your Switch into your PC via USB.</li><li>Your microSD card should now be accessible on your PC, open it.</li><li>Extract the Ultrahand <code>.zip</code> file to a location on your computer. <ul><li>If your archive manager allows for it, you can also simply open the <code>.zip</code> file directly.</li></ul></li><li>Copy the <em>contents</em> of the (extracted) <code>.zip</code> file to the root of your microSD card, then copy <code>ovlmenu.ovl</code> to <code>sd:/switch/.overlays</code>. <ul><li><strong>Optional:</strong> You can verify if you&#39;ve installed Ultrahand correctly, you should have a folder called <code>420000000007E51A</code> (nx-ovlloader) in <code>sd:/atmosphere/contents</code> and the <code>ovlmenu.ovl</code> (Ultrahand) file in <code>sd:/switch/.overlays</code>.</li></ul></li><li>Boot into CFW.</li></ol><h2 id="opening-ultrahand" tabindex="-1">Opening Ultrahand <a class="header-anchor" href="#opening-ultrahand" aria-label="Permalink to &quot;Opening Ultrahand&quot;">​</a></h2><p>Ultrahand can be opened by pressing <code>ZL</code> + <code>ZR</code> + <code>DPAD down</code>, assuming you use the default configuration.</p><p><img src="'+l+'" alt="ultrahand"></p><h2 id="commonly-used-ultrahand-overlays" tabindex="-1">Commonly used Ultrahand overlays <a class="header-anchor" href="#commonly-used-ultrahand-overlays" aria-label="Permalink to &quot;Commonly used Ultrahand overlays&quot;">​</a></h2><ul><li><a href="https://github.com/ppkantorski/Status-Monitor-Overlay/" target="_blank" rel="noreferrer">Status-Monitor-Overlay</a></li><li><a href="https://github.com/proferabg/EdiZon-Overlay" target="_blank" rel="noreferrer">EdiZon overlay</a></li><li><a href="https://github.com/nedex/QuickNTP" target="_blank" rel="noreferrer">QuickNTP</a></li><li><a href="https://github.com/XorTroll/emuiibo" target="_blank" rel="noreferrer">Emuiibo</a> (this requires you to also install the Emuiibo sysmodule)</li><li><a href="https://github.com/DefenderOfHyrule/TriPlayer" target="_blank" rel="noreferrer">TriPlayer</a> (this requires you to also install the TriPlayer sysmodule)</li><li><a href="https://github.com/DefenderOfHyrule/ldn_mitm" target="_blank" rel="noreferrer">ldn_mitm</a> (this requires you to also install the ldn_mitm sysmodule)</li><li><a href="https://github.com/averne/Fizeau" target="_blank" rel="noreferrer">Fizeau</a> (this requires you to also install the Fizeau sysmodule)</li><li><a href="https://github.com/TOM-BadEN/KeyX" target="_blank" rel="noreferrer">KeyX</a> (this requires you to also install the KeyX sysmodule)</li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="my-switch-crashes-on-boot-after-i-installed-ultrahand" tabindex="-1">My Switch crashes on boot after I installed Ultrahand!: <a class="header-anchor" href="#my-switch-crashes-on-boot-after-i-installed-ultrahand" aria-label="Permalink to &quot;My Switch crashes on boot after I installed Ultrahand!:&quot;">​</a></h3><p><strong>Cause:</strong> If your Switch crashes with Error code <code>2001-0123 (0xf601)</code> and Title ID <code>420000000007E51A</code>, you didn&#39;t successfully install Ultrahand or you aren&#39;t using the latest release of Ultrahand, re-follow the installation instructions above.</p><h3 id="my-switch-crashes-when-i-open-an-overlay-via-ultrahand" tabindex="-1">My Switch crashes when I open an overlay via Ultrahand!: <a class="header-anchor" href="#my-switch-crashes-when-i-open-an-overlay-via-ultrahand" aria-label="Permalink to &quot;My Switch crashes when I open an overlay via Ultrahand!:&quot;">​</a></h3><p><strong>Cause:</strong> If your Switch crashes with Error code <code>2001-0123 (0xf601)</code> and Title ID <code>420000000007E51A</code>, the overlay you&#39;re trying to open/use isn&#39;t up to date. Check its source repository for updates.</p><ul><li>If this overlay doesn&#39;t have an updated release, you may have to look for a forked (updated) release or compile it yourself using the latest <code>libultrahand</code> library. The latter is for developers (or advanced users).</li></ul><h3 id="ultrahand-isn-t-opening-when-i-press-the-correct-button-combination" tabindex="-1">Ultrahand isn&#39;t opening when I press the correct button combination!: <a class="header-anchor" href="#ultrahand-isn-t-opening-when-i-press-the-correct-button-combination" aria-label="Permalink to &quot;Ultrahand isn&#39;t opening when I press the correct button combination!:&quot;">​</a></h3><p>Assuming you&#39;ve followed the installation instructions successfully, this is probably due to the archive bit being set on one or more folders/files on your microSD card. This is usually the result of copying files to a microSD card via a Mac. If you are experiencing this issue, try running the archive bit fixer utility via hekate for all files.</p><p>This can be done by booting into hekate and going to <code>Tools</code> &gt; <code>Arch bit • RCM Touch • Pkg1/2</code> &gt; <code>Fix Archive Bit</code>.</p>',22)])])}const p=a(i,[["render",n]]);export{f as __pageData,p as default};
